invalid = {"case_id": 'CASO-ICA-050-1A', 'tasks': 40, 'slices': {'adversarial': 5, 'edge': 10, 'normal': 25}, 'rubric_levels': {0, 1, 2, 3}, 'holdout': 0}
incomplete = {"case_id": 'CASO-ICA-050-1A', 'tasks': 40, 'slices': {'adversarial': 5, 'edge': 10, 'normal': 25}, 'rubric_levels': {0, 1, 2, 3}}
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)

